class Solution(object):
    def minimumRightShifts(self, nums):
        n = len(nums)
        breaks = [i for i in range(n - 1) if nums[i] > nums[i + 1]]
        if not breaks:
            return 0
        if len(breaks) > 1:
            return -1
        i = breaks[0]
        if nums[-1] <= nums[0]:
            return n - 1 - i
        return -1
